#include <vector>
#include <queue>
#include <climits>
#include <unordered_map>
#include <utility>

using namespace std;

long long solve(long long n, vector<vector<long long>> edges) {
    // Build adjacency list: original edges and reversed edges (for possible flipping)
    vector<unordered_map<long long, long long>> adj(n);
    vector<vector<pair<long long, long long>>> reverse_adj(n); // to store incoming edges for each node

    for (const auto& e : edges) {
        long long u = e[0], v = e[1], w = e[2];
        adj[u][v] = w;
        reverse_adj[v].emplace_back(u, w);
    }

    // Dijkstra's setup: priority queue, distance array (with flip status)
    // dist[node][used_flip] = distance
    vector<vector<long long>> dist(n, vector<long long>(2, LLONG_MAX));
    using State = tuple<long long, long long, bool>; // (distance, node, used_flip)
    priority_queue<State, vector<State>, greater<State>> pq;

    dist[0][0] = 0;
    pq.emplace(0, 0, false);

    while (!pq.empty()) {
        auto [current_dist, u, used_flip] = pq.top();
        pq.pop();

        if (u == n - 1) {
            return current_dist;
        }

        if (current_dist > dist[u][used_flip]) {
            continue;
        }

        // Option 1: traverse original edges
        for (const auto& [v, w] : adj[u]) {
            if (current_dist + w < dist[v][used_flip]) {
                dist[v][used_flip] = current_dist + w;
                pq.emplace(dist[v][used_flip], v, used_flip);
            }
        }

        // Option 2: if not used flip yet, try flipping an incoming edge
        if (!used_flip) {
            for (const auto& [v, w] : reverse_adj[u]) {
                long long new_dist = current_dist + 2 * w;
                if (new_dist < dist[v][1]) {
                    dist[v][1] = new_dist;
                    pq.emplace(dist[v][1], v, true);
                }
            }
        }
    }

    long long result = min(dist[n - 1][0], dist[n - 1][1]);
    return result == LLONG_MAX ? -1 : result;
}

