function solve(n: number, edges: number[][]): number {
    // Build adjacency list for original edges
    const adj: Map<number, Map<number, number>> = new Map();
    // Build reverse adjacency list for incoming edges (for possible flipping)
    const reverseAdj: Map<number, [number, number][]> = new Map();

